// src/components/TimerDisplay.js
import React, { useState, useEffect } from 'react';
import './TimerDisplay.css';

const TimerDisplay = ({ isRunning, targetTime, selectedTiming, playDuration }) => {
  const [remainingTime, setRemainingTime] = useState(selectedTiming ? selectedTiming * 60 : 0);
  const [playStatus, setPlayStatus] = useState('待機中');
  
  useEffect(() => {
    if (!isRunning) {
      setPlayStatus('待機中');
      return () => {};
    }
    
    let interval;
    
    if (targetTime) {
      setPlayStatus('カウントダウン中');
      
      interval = setInterval(() => {
        const now = Date.now();
        const remaining = Math.max(0, targetTime - now);
        const remainingSeconds = Math.ceil(remaining / 1000);
        
        setRemainingTime(remainingSeconds);
        
        if (remaining <= 0) {
          setPlayStatus('再生中');
          clearInterval(interval);
        }
      }, 500);
    } else {
      setPlayStatus('再生中');
    }
    
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isRunning, targetTime]);
  
  // 残り時間の表示形式を計算
  const formatTime = (totalSeconds) => {
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes}:${seconds.toString().padStart(2, '0')}`;
  };
  
  return (
    <div className="timer-display">
      <div className="status-badge" data-status={playStatus}>
        <span>{playStatus}</span>
      </div>
      
      {isRunning && (
        <div className="time-remaining">
          {playStatus === 'カウントダウン中' ? (
            <>
              <div className="countdown-label">再生開始まで</div>
              <div className="countdown-time">{formatTime(remainingTime)}</div>
            </>
          ) : playStatus === '再生中' ? (
            <div className="playing-message">
              アファメーション再生中 ({playDuration}分間)
            </div>
          ) : null}
        </div>
      )}
      
      {!isRunning && (
        <div className="setup-message">
          {selectedTiming !== null && playDuration !== null ? (
            <p>
              {selectedTiming === 0 
                ? `睡眠直後から${playDuration}分間再生します` 
                : `睡眠から${selectedTiming}分後に${playDuration}分間再生します`}
            </p>
          ) : (
            <p>タイミングと再生時間を選択してください</p>
          )}
        </div>
      )}
    </div>
  );
};

export default TimerDisplay;