// src/App.js
import React, { useState, useCallback, useEffect } from 'react';
import Timer from './components/Timer';
import TimerDisplay from './components/TimerDisplay';
import audioService from './services/audioService';
import './App.css';
import './components/TimerDisplay.css';

function App() {
  const [isRunning, setIsRunning] = useState(false);
  const [volume, setVolume] = useState(0.3);
  const [selectedTiming, setSelectedTiming] = useState(null);
  const [playDuration, setPlayDuration] = useState(null);
  const [targetTime, setTargetTime] = useState(null);
  const [wakeLock, setWakeLock] = useState(null);
  const [isInitialized, setIsInitialized] = useState(false);
  
  // ページロード時に前回の設定を復元
  useEffect(() => {
    try {
      const savedSettings = localStorage.getItem('lucidDreamSettings');
      if (savedSettings) {
        const { timing, duration, volume: savedVolume } = JSON.parse(savedSettings);
        setSelectedTiming(timing);
        setPlayDuration(duration);
        setVolume(savedVolume);
        console.log('前回の設定を読み込みました');
      }
    } catch (error) {
      console.error('設定の読み込みエラー:', error);
    }
  }, []);

  // 初期化処理
  useEffect(() => {
    const initializeAudio = async () => {
      try {
        const result = await audioService.initialize();
        setIsInitialized(result);
        console.log('音声システムの初期化状態:', result);
      } catch (error) {
        console.error('初期化エラー:', error);
        setIsInitialized(false);
      }
    };

    // ユーザーインタラクション時に初期化
    const handleInteraction = async () => {
      if (!isInitialized) {
        await initializeAudio();
        requestWakeLock();
      }
      document.removeEventListener('touchstart', handleInteraction);
      document.removeEventListener('click', handleInteraction);
    };

    document.addEventListener('touchstart', handleInteraction);
    document.addEventListener('click', handleInteraction);

    return () => {
      document.removeEventListener('touchstart', handleInteraction);
      document.removeEventListener('click', handleInteraction);
      releaseWakeLock();
    };
  }, [isInitialized]);

  // スリープ防止のためのWake Lock
  const requestWakeLock = async () => {
    try {
      if ('wakeLock' in navigator) {
        const lock = await navigator.wakeLock.request('screen');
        setWakeLock(lock);
        console.log('Wake Lock が有効になりました');
        
        lock.addEventListener('release', () => {
          console.log('Wake Lock が解除されました - 再取得を試みます');
          // 画面がオンに戻ったときに再取得を試みる
          if (isRunning) {
            requestWakeLock();
          }
        });
      } else {
        console.log('Wake Lock APIが利用できないため、代替手段を使用します');
        // Wake Lock APIが使えない場合は、audioServiceのkeepAliveに頼る
      }
    } catch (err) {
      console.error('Wake Lock エラー:', err);
    }
  };
  
  const releaseWakeLock = () => {
    if (wakeLock) {
      wakeLock.release()
        .then(() => console.log('Wake Lock を手動解除しました'))
        .catch((err) => console.error('Wake Lock 解除エラー:', err));
      setWakeLock(null);
    }
  };

  const handleTimerSettings = useCallback((timing, duration) => {
    if (timing[0] !== undefined) {
      setSelectedTiming(timing[0]);
      console.log(`タイミング設定: ${timing[0]}分後`);
    }
    if (duration !== undefined) {
      setPlayDuration(duration);
      console.log(`再生時間設定: ${duration}分間`);
    }
    
    // 設定をLocalStorageに保存
    try {
      const settings = {
        timing: timing[0] !== undefined ? timing[0] : selectedTiming,
        duration: duration !== undefined ? duration : playDuration,
        volume
      };
      localStorage.setItem('lucidDreamSettings', JSON.stringify(settings));
    } catch (error) {
      console.error('設定の保存エラー:', error);
    }
  }, [selectedTiming, playDuration, volume]);

  const stopAll = () => {
    setIsRunning(false);
    setTargetTime(null);
    audioService.stop();
    releaseWakeLock();
  };

  const handleStart = async () => {
    console.log('ボタンがクリックされました');

    if (!isRunning) {
      // 初期化チェック
      if (!isInitialized) {
        const result = await audioService.initialize();
        setIsInitialized(result);
        if (!result) {
          alert('音声システムの初期化に失敗しました。ページを再読み込みしてください。');
          return;
        }
      }

      if (playDuration === null) {
        alert('再生時間を選択してください');
        return;
      }
      if (selectedTiming === null) {
        alert('再生タイミングを選択してください');
        return;
      }
      
      // スリープ防止を有効化
      await requestWakeLock();

      setIsRunning(true);
      const startTime = new Date().getTime();
      console.log(`開始時刻: ${new Date().toLocaleTimeString()}`);
      console.log(`${selectedTiming}分後に${playDuration}分間再生を開始します`);

      if (selectedTiming === 0) {
        // 即時再生
        console.log('即時再生を開始します');
        try {
          await audioService.playAffirmation(playDuration, volume);
        } catch (error) {
          console.error('再生エラー:', error);
          stopAll();
        }
      } else {
        // 時間指定再生
        const delayMs = selectedTiming * 60 * 1000;
        const target = startTime + delayMs;
        setTargetTime(target);
        
        console.log(`${selectedTiming}分後に再生を開始するようにタイマーをセット`);
        
        // 高精度タイマー
        const timer = setTimeout(async () => {
          console.log(`${selectedTiming}分が経過しました。再生を開始します`);
          console.log(`終了時刻: ${new Date().toLocaleTimeString()}`);
          
          const elapsedTime = (new Date().getTime() - startTime) / 1000 / 60;
          console.log(`実際の経過時間: ${elapsedTime.toFixed(2)}分`);
          
          setTargetTime(null);
          
          try {
            await audioService.playAffirmation(playDuration, volume);
          } catch (error) {
            console.error('再生エラー:', error);
            stopAll();
          }
        }, delayMs);
        
        // タイマークリアを保存
        window.currentTimer = timer;
      }
    } else {
      console.log('再生を停止します');
      if (window.currentTimer) {
        clearTimeout(window.currentTimer);
        window.currentTimer = null;
      }
      stopAll();
    }
  };

  // バックグラウンドでの時間ずれ検出
  useEffect(() => {
    if (!isRunning || !targetTime) return;
    
    let lastCheck = Date.now();
    const intervalId = setInterval(() => {
      const now = Date.now();
      const elapsed = now - lastCheck;
      
      // 10秒以上の時間ずれがある場合（端末がスリープして復帰した可能性）
      if (elapsed > 10000) {
        console.log(`時間ずれを検出: ${elapsed}ms経過`);
        // 現在時刻とtargetTimeを比較して必要な処理を実行
        if (now >= targetTime) {
          console.log('スリープ中にタイマー時間を超過しました。再生を開始します');
          setTargetTime(null);
          audioService.playAffirmation(playDuration, volume).catch(error => {
            console.error('再生エラー:', error);
            stopAll();
          });
        }
      }
      
      lastCheck = now;
    }, 1000);
    
    return () => clearInterval(intervalId);
  }, [isRunning, targetTime, playDuration, volume]);

  return (
    <div className="App">
      <header className="App-header">
        <h1>明晰夢誘導アプリ</h1>
        
        <Timer 
          onTimeSet={handleTimerSettings}
          isRunning={isRunning}
          initialTiming={selectedTiming}
          initialDuration={playDuration}
        />
        
        <TimerDisplay 
          isRunning={isRunning}
          targetTime={targetTime}
          selectedTiming={selectedTiming}
          playDuration={playDuration}
        />

        <div className="controls">
          <button 
            onClick={handleStart}
            className={`control-button ${isRunning ? 'running' : ''}`}
          >
            {isRunning ? '停止' : '開始'}
          </button>
        </div>
        
        <div className="volume-control">
          <label>音量: {Math.round(volume * 100)}%</label>
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={volume}
            onChange={(e) => {
              const newVolume = parseFloat(e.target.value);
              setVolume(newVolume);
              audioService.setVolume(newVolume);
              
              // 音量設定も保存
              try {
                const savedSettings = localStorage.getItem('lucidDreamSettings');
                if (savedSettings) {
                  const settings = JSON.parse(savedSettings);
                  settings.volume = newVolume;
                  localStorage.setItem('lucidDreamSettings', JSON.stringify(settings));
                }
              } catch (error) {
                console.error('音量設定の保存エラー:', error);
              }
            }}
          />
        </div>
        
        <div className="app-info">
          <p>このアプリは明晰夢誘導のため、設定したタイミングでアファメーションを再生します</p>
          <p className="version">バージョン: 1.1.0</p>
        </div>
      </header>
    </div>
  );
}

export default App;