// src/components/Timer.js
import React, { useState, useEffect } from 'react';

function Timer({ onTimeSet, isRunning, initialTiming, initialDuration }) {
  const [selectedTiming, setSelectedTiming] = useState(initialTiming || null);
  const [duration, setDuration] = useState(initialDuration || null);

  // 初期値の適用
  useEffect(() => {
    if (initialTiming !== null && initialTiming !== undefined && selectedTiming === null) {
      setSelectedTiming(initialTiming);
    }
    if (initialDuration !== null && initialDuration !== undefined && duration === null) {
      setDuration(initialDuration);
    }
  }, [initialTiming, initialDuration, selectedTiming, duration]);

  useEffect(() => {
    if (selectedTiming !== null) {
      onTimeSet([selectedTiming], duration);
    }
  }, [selectedTiming, duration, onTimeSet]);

  const timingOptions = [
    { value: 0, label: '睡眠直後' },
    { value: 1, label: '1分後' },
    { value: 5, label: '5分後' },
    { value: 10, label: '10分後' },
    { value: 15, label: '15分後' },
    { value: 20, label: '20分後' },
    { value: 30, label: '30分後' },
    { value: 45, label: '45分後' },
    { value: 60, label: '60分後' }
  ];

  const durationOptions = [
    { value: 1, label: '1分' },
    { value: 5, label: '5分' },
    { value: 10, label: '10分' },
    { value: 15, label: '15分' }
  ];

  const handleTimingChange = (timing) => {
    if (!isRunning) {
      setSelectedTiming(timing);
    }
  };

  return (
    <div className="timer-settings">
      <h2>タイミング設定</h2>
      <div className="timing-options">
        {timingOptions.map(option => (
          <label 
            key={option.value} 
            className={`timing-option ${selectedTiming === option.value ? 'selected' : ''} ${isRunning ? 'disabled' : ''}`}
          >
            <input
              type="radio"
              name="timing"
              checked={selectedTiming === option.value}
              onChange={() => handleTimingChange(option.value)}
              disabled={isRunning}
            />
            {option.label}
          </label>
        ))}
      </div>
      
      <h3>再生時間</h3>
      <div className="duration-options">
        {durationOptions.map(option => (
          <label 
            key={option.value} 
            className={`duration-option ${duration === option.value ? 'selected' : ''} ${isRunning ? 'disabled' : ''}`}
          >
            <input
              type="radio"
              name="duration"
              value={option.value}
              checked={duration === option.value}
              onChange={(e) => !isRunning && setDuration(Number(e.target.value))}
              disabled={isRunning}
            />
            {option.label}
          </label>
        ))}
      </div>
    </div>
  );
}

export default Timer;