// src/services/audioService.js
class AudioService {
  constructor() {
    this.audioContext = null;
    this.audioBuffer = null;
    this.gainNode = null;
    this.source = null;
    this.isPlaying = false;
    this.currentVolume = 0.3;
    this.isInitialized = false;
    this.playTimer = null;
    this.silentAudio = null; // スリープ防止用の無音オーディオ
    this.intervalId = null; // バックグラウンド監視用
    this.lastCheckTime = 0; // 時間ずれ検出用
  }

  async initialize() {
    if (this.isInitialized) {
      return true;
    }

    try {
      console.log('音声システムの初期化を開始');

      // AudioContextの初期化
      this.audioContext = new (window.AudioContext || window.webkitAudioContext)();
      
      // GainNodeの設定
      this.gainNode = this.audioContext.createGain();
      this.gainNode.connect(this.audioContext.destination);
      this.gainNode.gain.value = this.currentVolume;
      
      // 音声ファイルの読み込み（Buffer方式に変更）
      await this.loadAudioFile('/lucid-dream-app/audio/affirmation.mp3');
      
      // スリープ防止用の無音オーディオ設定
      this.setupSilentAudio();
      
      await this.audioContext.resume();
      
      this.isInitialized = true;
      console.log('音声システムの初期化完了');
      return true;
    } catch (error) {
      console.error('初期化エラー:', error);
      this.isInitialized = false;
      return false;
    }
  }
  
  async loadAudioFile(url) {
    try {
      const response = await fetch(url);
      const arrayBuffer = await response.arrayBuffer();
      this.audioBuffer = await this.audioContext.decodeAudioData(arrayBuffer);
      console.log('音声ファイルの読み込み完了');
    } catch (error) {
      console.error('音声ファイル読み込みエラー:', error);
      throw error;
    }
  }
  
  setupSilentAudio() {
    // iOS/Safari向けの無音オーディオループ（スリープ防止用）
    this.silentAudio = new Audio();
    this.silentAudio.src = 'data:audio/mp3;base64,';
    this.silentAudio.loop = true;
    this.silentAudio.volume = 0.001; // 最小音量
    this.silentAudio.playsinline = true;
  }
  
  startKeepAlive() {
    // スリープ防止の開始
    try {
      this.silentAudio.play().catch(e => console.error('無音再生エラー:', e));
      
      // 時間ずれの検出と補正（バックグラウンド対策）
      this.lastCheckTime = Date.now();
      this.intervalId = setInterval(() => {
        const now = Date.now();
        const elapsed = now - this.lastCheckTime;
        
        // 予想より大幅に時間が経過していた場合（スリープからの復帰など）
        if (elapsed > 10000) { // 10秒以上のずれ
          console.log(`時間ずれを検出: ${elapsed}ms経過`);
          // 必要な処理（例：音声の再開など）
          if (this.isPlaying && this.source) {
            // 再生が中断されていたかもしれないので再開
            this.restartAudio();
          }
        }
        
        this.lastCheckTime = now;
      }, 1000);
      
    } catch (error) {
      console.error('KeepAlive開始エラー:', error);
    }
  }
  
  restartAudio() {
    try {
      // 現在の再生が停止していた場合、再開
      if (this.isPlaying && this.audioContext.state !== 'running') {
        this.audioContext.resume();
        console.log('音声の再生を再開しました');
      }
    } catch (error) {
      console.error('再開エラー:', error);
    }
  }
  
  stopKeepAlive() {
    try {
      if (this.silentAudio) {
        this.silentAudio.pause();
        this.silentAudio.currentTime = 0;
      }
      
      if (this.intervalId) {
        clearInterval(this.intervalId);
        this.intervalId = null;
      }
    } catch (error) {
      console.error('KeepAlive停止エラー:', error);
    }
  }

  async playAffirmation(duration, volume) {
    if (this.isPlaying) {
      console.log('既に再生中です');
      return;
    }

    try {
      if (!this.isInitialized) {
        await this.initialize();
      }

      this.isPlaying = true;
      this.currentVolume = volume;
      
      // スリープ防止の開始
      this.startKeepAlive();

      // 音量の初期化
      this.gainNode.gain.setValueAtTime(0, this.audioContext.currentTime);
      
      // バッファからのソース作成（AudioBufferSourceNode）
      this.source = this.audioContext.createBufferSource();
      this.source.buffer = this.audioBuffer;
      this.source.connect(this.gainNode);
      this.source.loop = true; // ループ再生
      
      // 再生開始
      this.source.start();
      console.log(`再生を開始しました（${duration}分間、音量:${Math.round(this.currentVolume * 100)}%）`);

      // フェードイン（3秒）
      this.gainNode.gain.linearRampToValueAtTime(
        this.currentVolume,
        this.audioContext.currentTime + 3
      );

      // 再生時間の設定
      this.playTimer = setTimeout(() => {
        this.stop();
        console.log(`${duration}分間の再生が完了しました`);
      }, duration * 60 * 1000);

      // ページが見えなくなったときのイベント
      document.addEventListener('visibilitychange', this.handleVisibilityChange);

    } catch (error) {
      console.error('再生エラー:', error);
      this.isPlaying = false;
      throw error;
    }
  }
  
  // visibilitychangeイベントハンドラ
  handleVisibilityChange = () => {
    if (document.hidden) {
      console.log('ページがバックグラウンドになりました');
      // バックグラウンド時に必要な処理があれば実行
    } else {
      console.log('ページがフォアグラウンドに戻りました');
      if (this.isPlaying) {
        // 再生が中断されていたかもしれないので再開
        this.restartAudio();
      }
    }
  };

  setVolume(volume) {
    this.currentVolume = volume;
    if (this.gainNode) {
      // 音量変更をなめらかに（0.2秒）
      this.gainNode.gain.linearRampToValueAtTime(
        volume, 
        this.audioContext.currentTime + 0.2
      );
    }
  }

  async stop() {
    if (!this.isPlaying) return;

    try {
      // visibilitychangeリスナーを削除
      document.removeEventListener('visibilitychange', this.handleVisibilityChange);
      
      // スリープ防止の停止
      this.stopKeepAlive();
      
      // フェードアウト（0.5秒）
      const currentTime = this.audioContext.currentTime;
      this.gainNode.gain.linearRampToValueAtTime(0, currentTime + 0.5);

      setTimeout(() => {
        if (this.source) {
          this.source.stop();
          this.source = null;
        }
        
        this.isPlaying = false;
        console.log('再生を停止しました');
      }, 500);

      if (this.playTimer) {
        clearTimeout(this.playTimer);
        this.playTimer = null;
      }
    } catch (error) {
      console.error('停止エラー:', error);
    }
  }
}

const audioServiceInstance = new AudioService();
export default audioServiceInstance;