// src/index.js
import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';
import * as serviceWorker from './serviceWorker';

// スリープ後の状態復元用にunloadイベントをキャプチャ
window.addEventListener('beforeunload', () => {
  // タイマー実行中であれば、その状態を保存
  if (window.isTimerRunning) {
    const timerData = {
      isRunning: true,
      targetTime: window.targetTime,
      selectedTiming: window.selectedTiming,
      playDuration: window.playDuration,
      volume: window.currentVolume,
      timestamp: Date.now()
    };
    
    try {
      localStorage.setItem('lucidDreamTimer', JSON.stringify(timerData));
    } catch (error) {
      console.error('タイマー状態の保存エラー:', error);
    }
  }
});

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://bit.ly/CRA-PWA
serviceWorker.register(); // オフライン対応のためregisterに変更